        $query->where('account_id', $account->id)
            ->where('status', \App\Enums\AccountProductStatus::Active->value)
            ->where(function (Builder $builder): void {
                $builder->whereNull('expires_at')
                    ->orWhere('expires_at', '>', now());
            });
    })
